module reg16(
    input clk,
    input rst,
    input en,
    input [15:0] data_in,

    output reg [15:0] data_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
begin
  if (rst)
    data_out <= 16'b0000000000000000;
  else if (en)
    data_out <= data_in;
end

endmodule
